use postgres::{Client, Error, NoTls};
use std::collections::HashMap;

fn search_users_by_email(client: &mut Client, email: &str) -> Result<Vec<HashMap<String, serde_json::Value>>, Error> {
    let query = "SELECT * FROM users WHERE email = $1";
    let rows = client.query(query, &[&email])?;
    
    let mut results = Vec::new();
    
    for row in rows {
        let mut user_map = HashMap::new();
        
        for (i, column) in row.columns().iter().enumerate() {
            let value: Option<String> = row.get(i);
            user_map.insert(column.name().to_string(), serde_json::Value::from(value));
        }
        
        results.push(user_map);
    }
    
    Ok(results)
}